var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"좋아…… 이제 다 됐어요.","JPN":"よし……できました。","ENG":"All right... It’s all done.","TWN":"OK……大功告成！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"음? 자, 잠깐 이건……!?","JPN":"うん？　ちょ、ちょっと、これって……！？","ENG":"Mm? W-wait... Is this...?","TWN":"嗯？這…這是……！？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……미리네?","JPN":"……マリ？","ENG":"…Rinae?","TWN":"……宓璃奈？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이, 이기 뭐꼬!?","JPN":"な、なんやこれ！？","ENG":"W-what in the name of...!","TWN":"你…你幹啥你！？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니 미쳤나!? 갑자기 와 내를 그리는 긴데!? 니 내한테 반한기가!?","JPN":"あんた、頭どうかしたん！？　なんでいきなりウチを描くん！？　ウチに惚れたんか！？","ENG":"Have you lost it, kid? What are ya fooling about, huh?! Are you into me or somethin’?","TWN":"你瘋啦？為啥突然要畫我！？你是愛上我喔？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"무, 무슨 소리에요! 그럴 리가 없잖아요! 좀 더 자세히 보시라고요!","JPN":"な、何を言ってるんですか！　そんなわけないでしょう！　もっとちゃんと見てください！","ENG":"W-what?! Don’t be ridiculous! Look closer!","TWN":"胡…胡說八道！想也知道不可能！你再看仔細一點！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"호오, 이건 스트리트 카운터의 인게임 일러스트랑 스타일이 거의 흡사한데요?","JPN":"ほう、これはストリート・カウンターのインゲームイラストとほぼ同じスタイルだね。","ENG":"Ho-oh, this looks extremely similar to the in-game illustrations of Street Counter.","TWN":"哇喔，和街頭制裁者遊戲中的立繪感覺好像喔？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실력이 대단하네요, 조금만 다듬으면 바로 인게임 리소스로도 사용해도 괜찮을 정도에요.","JPN":"素晴らしい実力だ。もう少しブラッシュアップすれば、すぐインゲームイラストとして使ってもいいくらいだよ。","ENG":"You're extremely talented. A bit more tidying up, and it’ll be ready to be used as a resource.","TWN":"很厲害呢，只需要再微調一下，直接拿來當作遊戲素材似乎也沒問題。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"본 적 있어……. 이 그림체.","JPN":"見たことある……この画風。","ENG":"I’ve seen it before... This art style.","TWN":"我有看過……這個畫風。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이거 <color=#ffd34c>박스X</color>의 그림이야…… 오에카키에서 격투 게임 팬아트를 그리는.","JPN":"これ、<color=#ffd34c>ダンボールX</color>の絵……お絵かきで格ゲーのファンアート描いてる。","ENG":"This is <color=#ffd34c>Box X</color>... On Oekaki, he uploads fighting game fanart.","TWN":"這是<color=#ffd34c>BOX X</color>的畫風……他都會在線上繪圖版發表他的格鬥遊戲二創圖。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 박스X라고? 금마 존잘 일러레 아이가?","JPN":"ええっ？　ダンボールXやて？　あのめっちゃ絵がうまいイラストレーター？","ENG":"Eh? Box X? Ain’t he some super prodigy or something?","TWN":"你說啥？BOX X？很會畫人物的繪師？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 일러레가 이런 얼라라고? 내는 좀 더 어른인 줄 알았는데?","JPN":"あのイラストレーターがこんなガキなん？　ウチはもっと大人やと思っとったわ。","ENG":"You're tellin' me that this kid right here is Box X? I thought he was a grownup!","TWN":"你說這個小朋友就是他？我還以為會比他再大一點呢？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"앗!? 그럼, 설마 박스X라는 닉네임도 스트리트 카운터에서 따온기가?","JPN":"あっ！？　じゃあ、まさかダンボールXってネームもストリート・カウンターから取ってきたん？","ENG":"Oh?! Is the name \\"Box X\\" an homage to Street Counter?!","TWN":"嗯！？該不會BOX X這個暱稱也是模仿街頭制裁者的嗎？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"맞아요, 제가 그림을 시작하게 된 게 바로 스트리트 카운터 때문이었거든요.","JPN":"そうですよ、僕が絵を描き始めたきっかけがストリート・カウンターでしたから。","ENG":"Yes, Street Counter was the sole reason why I started drawing.","TWN":"沒錯，街頭制裁者就是我的繪畫啟蒙。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그래서 스트리트 카운터는 저에게 무척 소중한 게임이에요.","JPN":"なのでストリート・カウンターは僕にとって、とても大事なゲームなんです。","ENG":"It’s that precious to me.","TWN":"所以街頭制裁者對我來說是非常重要的遊戲。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그 좋아하는 마음만큼은 여기 있는 누구에게도 지지 않는다고요.","JPN":"その気持ちだけはここにいる誰にも負けません。","ENG":"My love and passion for Street Counter wouldn’t be less than anyone here.","TWN":"我敢說，我對\\"街制\\"的熱愛是不會輸給任何人的！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……꼬맹이.","JPN":"……じゃりんこ。","ENG":"...Kiddo.","TWN":"……小朋友。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};